import Foundation

// MARK: - Environment Configuration

enum APIEnvironment {
    case development
    case staging
    case production

    var baseURL: URL {
        switch self {
        case .development:
            return URL(string: "https://dev.api.example.com")!
        case .staging:
            return URL(string: "https://staging.api.example.com")!
        case .production:
            return URL(string: "https://api.example.com")!
        }
    }
}

// MARK: - API Error Handling

enum APIError: Error, LocalizedError {
    case invalidURL
    case requestFailed(Error)
    case invalidResponse
    case decodingFailed(Error)
    case serverError(statusCode: Int, data: Data?)
    case unauthorized // For 401
    case badRequest // For 400
    case notFound // For 404
    case noData

    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "The API endpoint URL is invalid."
        case .requestFailed(let error):
            return "Network request failed: \(error.localizedDescription)"
        case .invalidResponse:
            return "Received an invalid response from the server."
        case .decodingFailed(let error):
            return "Failed to decode server response: \(error.localizedDescription)"
        case .serverError(let statusCode, _):
            return "Server returned an error with status code: \(statusCode)"
        case .unauthorized:
            return "Authentication required or failed."
        case .badRequest:
            return "The request was invalid."
        case .notFound:
            return "The requested resource was not found."
        case .noData:
            return "No data received from the server."
        }
    }
}

// MARK: - API Service

final class APIService {
    private let environment: APIEnvironment
    private let session: URLSession

    // In a real app, you might use a token manager
    private var authToken: String? {
        // Example: Retrieve from UserDefaults or KeyChain
        // UserDefaults.standard.string(forKey: "userAuthToken")
        return nil // Replace with actual token retrieval
    }

    init(environment: APIEnvironment, session: URLSession = .shared) {
        self.environment = environment
        self.session = session
    }

    // MARK: - Public Methods

    func get<T: Decodable>(path: String, queryItems: [URLQueryItem]? = nil, responseType: T.Type) async throws -> T {
        try await performRequest(method: "GET", path: path, queryItems: queryItems, body: nil, responseType: responseType)
    }

    func post<T: Decodable, U: Encodable>(path: String, body: U, responseType: T.Type) async throws -> T {
        let encoder = JSONEncoder()
        encoder.outputFormatting = .prettyPrinted // For readability in debugging, remove for production
        let httpBody = try encoder.encode(body)
        return try await performRequest(method: "POST", path: path, body: httpBody, responseType: responseType)
    }

    // MARK: - Private Request Handling

    private func createRequest(method: String, path: String, queryItems: [URLQueryItem]?, body: Data?) throws -> URLRequest {
        var urlComponents = URLComponents(url: environment.baseURL, resolvingAgainstBaseURL: true)
        urlComponents?.path += path
        urlComponents?.queryItems = queryItems

        guard let url = urlComponents?.url else {
            throw APIError.invalidURL
        }

        var request = URLRequest(url: url)
        request.httpMethod = method
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        request.addValue("application/json", forHTTPHeaderField: "Accept")

        if let token = authToken {
            request.addValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        request.httpBody = body
        return request
    }

    private func performRequest<T: Decodable>(method: String, path: String, queryItems: [URLQueryItem]? = nil, body: Data? = nil, responseType: T.Type) async throws -> T {
        let request = try createRequest(method: method, path: path, queryItems: queryItems, body: body)

        let (data, response) = try await session.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.invalidResponse
        }

        guard 200..<300 ~= httpResponse.statusCode else {
            switch httpResponse.statusCode {
            case 400: throw APIError.badRequest
            case 401: throw APIError.unauthorized
            case 404: throw APIError.notFound
            default: throw APIError.serverError(statusCode: httpResponse.statusCode, data: data)
            }
        }

        if data.isEmpty && T.self == EmptyResponse.self {
             return EmptyResponse() as! T
        }

        guard !data.isEmpty else {
            throw APIError.noData
        }

        let decoder = JSONDecoder()
        decoder.keyDecodingStrategy = .convertFromSnakeCase // Common for many APIs
        do {
            return try decoder.decode(responseType, from: data)
        } catch {
            print("Decoding Error: \(error)")
            print("Received Data: \(String(data: data, encoding: .utf8) ?? "N/A")")
            throw APIError.decodingFailed(error)
        }
    }
