// MARK: - Example Usage (Models and Endpoints)

// Define your API response models
struct User: Codable, Identifiable {
    let id: Int
    let name: String
    let email: String
    let createdAt: Date // Example: if server returns ISO8601 string
}

struct AuthRequest: Codable {
    let username: String
    let passwordPlaintext: String // For MVP, but consider hashing or secure alternatives
}

struct AuthResponse: Codable {
    let token: String
    let userId: Int
    let expiresIn: Int // Example: seconds until token expires
}

// A helper type for requests that expect no specific data in the response body (e.g., a simple success 200 OK)
struct EmptyResponse: Codable {}


// MARK: - API Endpoints Facade (Optional but Recommended)

protocol UserAPI {
    func getUsers() async throws -> [User]
    func getUser(id: Int) async throws -> User
    func login(credentials: AuthRequest) async throws -> AuthResponse
    func register(user: User) async throws -> EmptyResponse // Assuming register returns 200 OK with no body
}

class DefaultUserAPI: UserAPI {
    private let apiService: APIService

    init(apiService: APIService) {
        self.apiService = apiService
    }

    func getUsers() async throws -> [User] {
        try await apiService.get(path: "/users", responseType: [User].self)
    }

    func getUser(id: Int) async throws -> User {
        try await apiService.get(path: "/users/\(id)", responseType: User.self)
    }

    func login(credentials: AuthRequest) async throws -> AuthResponse {
        try await apiService.post(path: "/auth/login", body: credentials, responseType: AuthResponse.self)
    }

    func register(user: User) async throws -> EmptyResponse {
        // Note: For User registration, 'user' might need to be a different type (e.g., RegisterRequest)
        // that only includes fields necessary for registration, not all User fields like 'id' or 'createdAt'.
        // For simplicity in MVP, we use the User model directly.
        try await apiService.post(path: "/auth/register", body: user, responseType: EmptyResponse.self)
    }
}

